{% extends "_base/base.html.j2" %}

{#====================================================================
  LINE-ITEM DOCUMENT STRUCTURE. This file is the STRUCTURE — regions,
  data binding, partials, translations. To design a new look: clone this
  document and edit ONLY the css (the skin). Text uses {{ L.<key> }}
  (maintain via set_translation); layout classes live in css.
  Available regions (data-box): recipient · info · subject · intro ·
  items · totals · payment · notes · ship-to. Extra building blocks as
  partials: contact_person, ship_to.
====================================================================#}

{% block title %}{{ L.doc_title }} {{ data.documentNumber }}{% endblock %}

{% set buyer = data.documentAddress | default({}) %}
{% set sold  = ((data.effectiveAddresses or {}).soldTo) | default(buyer) %}
{% set ship  = ((data.effectiveAddresses or {}).shipTo) | default({}) %}
{% set items = data.lineItems | default([]) %}
{% set pay   = data.payment | default({}) %}

{% set _ship_differs = ship and ship.name and (
     (ship.street or '') != (sold.street or '')
     or (ship.zipCode or '') != (sold.zipCode or '')
     or (ship.name or '') != (sold.name or '')
) %}

{#- HEADER (Briefkopf): Logo + Firmenblock. Das ist DIE Kopfzeile — hier
   bearbeiten; KEINE zweite Kopfzeile im Inhalt zeichnen. Die Seitenzahl
   steht im Footer (css @bottom-center), nie oben rechts. Dieser Block
   ueberschreibt den Base-Default, damit der Header im Template sichtbar ist. -#}
{% block letterhead %}
  <div class="doc-header__brand">
    {% if assets.logo %}
      <img src="{{ assets.logo }}" alt="{{ data.company.name | default('') }}" class="doc-header__logo">
    {% else %}
      <div class="doc-header__wordmark"><strong>{{ data.company.name | default('') }}</strong></div>
    {% endif %}
    {% if data.company.address %}<p class="doc-header__sender">{{ data.company.address }}</p>{% endif %}
  </div>
  <div class="doc-header__contact">
    {% if data.company.phone %}<div>{{ data.company.phone }}</div>{% endif %}
    {% if data.company.email %}<div>{{ data.company.email }}</div>{% endif %}
    {% if data.company.website %}<div>{{ data.company.website }}</div>{% endif %}
  </div>
{% endblock %}

{% block content %}

  {#- Header row: recipient address left, document metadata right. -#}
  <div class="head-cols">
    <div class="head-cols__addr">
      {% with buyer=buyer, title=L.doc_title %}
        {% include "_base/_partials/recipient.html.j2" %}
      {% endwith %}
    </div>
    <div class="head-cols__info">
      <section class="box-info" data-box="info" aria-labelledby="info-heading">
        <h2 id="info-heading" class="visually-hidden">{{ L.doc_title }}</h2>
        <table>
          <tbody>
            {% if data.documentDate %}<tr><th scope="row">{{ L.doc_date }}</th><td>{{ data.documentDate }}</td></tr>{% endif %}
            {% if data.customerNumber %}<tr><th scope="row">{{ L.customer_number }}</th><td>{{ data.customerNumber }}</td></tr>{% endif %}
            {% if data.customerOrderNumber %}<tr><th scope="row">{{ L.order_ref }}</th><td>{{ data.customerOrderNumber }}</td></tr>{% endif %}
            {% if buyer.vatId %}<tr><th scope="row">{{ L.customer_vat }}</th><td>{{ buyer.vatId }}</td></tr>{% endif %}
          </tbody>
        </table>
      </section>
    </div>
  </div>

  {#- Subject (exactly one <h1> in the document). -#}
  <section class="box-subject" data-box="subject">
    <h1>{{ L.doc_title }} {{ data.documentNumber }}</h1>
  </section>

  {#- Intro line. -#}
  <section class="box-intro" data-box="intro"><p>{{ L.intro }}</p></section>

  {#- Items table. `columns` picks the columns (order matters):
      pos | sku | article | qty | unit | unit_price | vat | total.
      This 6-column set matches the base.css default column widths. -#}
  {% with title=L.positions, caption=L.positions, items=items, labels=L,
          columns=['pos','article','qty','unit_price','vat','total'] %}
    {% include "_base/_partials/items.html.j2" %}
  {% endwith %}

  {#- Totals (net, VAT breakdown via groupby, gross). -#}
  {% with items=items, totals=(data.totals or {}), labels=L %}
    {% include "_base/_partials/totals.html.j2" %}
  {% endwith %}

  {#- Payment details (only when an IBAN is present). -#}
  {% if pay.iban %}
  <section class="box-payment" data-box="payment" aria-labelledby="pay-heading">
    <h2 id="pay-heading">{{ L.payment_heading }}</h2>
    <dl class="pay-grid">
      <dt>{{ L.iban }}</dt><dd>{{ pay.iban }}</dd>
      {% if pay.bic %}<dt>{{ L.bic }}</dt><dd>{{ pay.bic }}</dd>{% endif %}
      {% if pay.bankName %}<dt>{{ L.bank }}</dt><dd>{{ pay.bankName }}</dd>{% endif %}
    </dl>
  </section>
  {% endif %}

  {#- Free-text notes / terms. -#}
  {% if data.bodyOutroduction %}
  <section class="box-notes" data-box="notes" aria-labelledby="notes-heading">
    <h2 id="notes-heading">{{ L.notes_heading }}</h2>
    <p>{{ data.bodyOutroduction }}</p>
  </section>
  {% endif %}

  {#- Alternate shipping address (only when it differs from the billing address). -#}
  {% if _ship_differs %}
    {% with ship=ship, title=L.ship_to %}
      {% include "_base/_partials/ship_to.html.j2" %}
    {% endwith %}
  {% endif %}

{% endblock %}

