/* ===================================================================
   SKIN — this is where the LOOK is designed. This css cascades after
   base.css and overrides its neutral defaults. Everything is free to
   change: colors, type, tables, spacing. The STRUCTURE (html, regions,
   data binding) stays untouched.

   Fastest start: set the design tokens in :root, then add individual
   .box-* / .positions-table / .totals-table rules.
   =================================================================== */

/* :root {
     --fs-body: 10pt;
     --col-qty: 20mm; --col-unit-price: 26mm; --col-vat: 14mm; --col-total: 28mm;
   } */

/* --- Header: address left, info block right (structural layout) --- */
.head-cols { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin: 8mm 0 6mm; }
.head-cols__addr { flex: 1 1 auto; min-width: 0; }
.head-cols__addr .box-recipient { margin: 0; }
.head-cols__info { flex: 0 0 64mm; }
.head-cols__info .box-info { margin: 0; }
.head-cols__info .box-info table { width: 100%; border-collapse: collapse; }
.head-cols__info .box-info th { white-space: nowrap; padding: 0.6mm 4mm 0.6mm 0; }
.head-cols__info .box-info td { text-align: right; }

/* --- Payment grid --- */
.pay-grid { display: grid; grid-template-columns: 24mm 1fr; gap: 0.5mm 4mm; margin: 0; font-size: 9.5pt; }
.pay-grid dt { color: #6b7280; }
.pay-grid dd { margin: 0; }

/* --- Page footer: every page gets a page number (BOTTOM, not top) plus the
   mandatory legal/contact lines, via @page margin boxes. These are literal
   placeholder strings — CSS is NOT Jinja-rendered, so fill them from the
   tenant's company data (officeLines / identityLines / bankLines) at author
   time, one line per \A. Do not use position:fixed — margin boxes work on
   both render engines, and never put the page number in @top-*. --- */
@page {
  @top-right { content: none; }
  @bottom-left {
    content: "Beispiel Handels GmbH \00b7 Marktplatz 1, 10115 Berlin \A Amtsgericht Charlottenburg \00b7 HRB 123456 \A Gesch\00e4ftsf\00fchrer: Max Beispiel";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line; vertical-align: top; padding-top: 4mm;
  }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.5pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 4mm;
  }
  @bottom-right {
    content: "USt-IdNr. DE123456789 \00b7 St.-Nr. 13/456/78901 \A Commerzbank Berlin \00b7 BIC COBADEFFXXX \A IBAN DE89 3704 0044 0532 0130 00";
    font-size: 6.5pt; line-height: 1.4; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm;
  }
}
